import { useState, useEffect, useRef } from "react";
import { motion, useScroll, useTransform, AnimatePresence } from "framer-motion";
import {
  ShoppingBag, Search, Heart, Menu, X, ArrowLeft, Star, Sparkles,
  Award, Gem, Scissors, Truck, ShieldCheck, RefreshCw, MapPin,
  Phone, Mail, Plus, Check, Quote, Settings, Minus, Trash2,
  ChevronRight, Package, AlertCircle,
} from "lucide-react";
import { StoreProvider, useStore, Product } from "./context/StoreContext";
import { LanguageProvider, useLang } from "./context/LanguageContext";
import AdminDashboard from "./components/AdminDashboard";
import LanguageSwitcher from "./components/LanguageSwitcher";

